#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int findMaximumXOR(int* nums, int numsSize) {
    int max_xor = 0;
    for (int i = 0; i < numsSize; i++) {
        for (int j = i + 1; j < numsSize; j++) {
            max_xor = max(max_xor, nums[i] ^ nums[j]);
        }
    }
    return max_xor;
}
int main() {
    int n;
    scanf("%d", &n);
    int nums[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &nums[i]);
    }
    printf("%d\n", findMaximumXOR(nums, n));
    return 0;
}

